const RICH_ALLOWED={
  status:new Set(["core","repo","tasks","memory","proposals","system"]),
  list:new Set(["tasks","goals","memory","proposals","plan"]),
  report:new Set(["core","work","self_apply"]),
  check:new Set(["keys","blockers","active_target","pending","live"]),
};
const RICH_DEFAULT={status:"core",list:"tasks",report:"work",check:"blockers"};
const CAPABILITY_REGISTRY={
  safe_command_add:{status:"active",risk:"low",source_verify:true,live_verify:true,rollback:true,allowed_paths:["active_target"],notes:"static text command only"},
  rich_command_add:{status:"active",risk:"medium",source_verify:true,live_verify:true,rollback:true,allowed_paths:["active_target"],notes:"whitelist template status/list/report/check only"},
  add_marker:{status:"active",risk:"low",source_verify:true,live_verify:false,rollback:true,allowed_paths:["active_target"],notes:"SELF_APPLY_MARKERS/help marker only"},
};
const FORBIDDEN_CAPABILITIES=["manual","arbitrary_js","wrangler.toml","external_fetch","secrets_write","delete_file"];

const now=()=>new Date().toISOString();
const clip=(v,n=3900)=>String(v??"").slice(0,n);
const uid=p=>`${p}_${crypto.randomUUID().slice(0,8)}`;
const clean=p=>String(p||"").trim().replace(/^\/+/,"");
const safe=p=>{const x=clean(p);return x&&!x.includes("..")&&x.length<180&&/^[\w./-]+$/.test(x)?x:null};
const out=(data,status=200)=>new Response(JSON.stringify(data,null,2),{status,headers:H});

function parse(update){const m=update?.message||update?.edited_message;if(!m)return null;const text=String(m.text||"").trim();let command=null,args="";if(text.startsWith("/")){const i=text.indexOf(" ");command=(i<0?text:text.slice(0,i)).replace(/@\w+$/,"").trim().toLowerCase();args=i<0?"":text.slice(i+1).trim()}return{chatId:m.chat?.id,userId:m.from?.id,text,command,args}}
async function kvText(env,key){return String(await env.MINISKYNET_KV.get(key)||"").trim()}
async function kvGet(env,key,fallback){const raw=await env.MINISKYNET_KV.get(key);if(!raw)return fallback;try{return JSON.parse(raw)}catch{return fallback}}
async function kvPut(env,key,value){await env.MINISKYNET_KV.put(key,JSON.stringify(value,null,2))}
async function arr(env,key){const v=await kvGet(env,key,{[key]:[]});return Array.isArray(v?.[key])?v[key]:[]}
async function saveArr(env,key,items,limit=100){await kvPut(env,key,{[key]:items.slice(-limit)})}
async function cfg(env){return{
  telegram:String(env.TELEGRAM_BOT_TOKEN||"").trim()||await kvText(env,"config:TELEGRAM_BOT_TOKEN"),
  owner:String(env.TELEGRAM_ALLOWED_USER_ID||"").trim()||await kvText(env,"config:TELEGRAM_ALLOWED_USER_ID"),
  openrouter:String(env.OPENROUTER_API_KEY||"").trim()||await kvText(env,"config:OPENROUTER_API_KEY"),
  gh:String(env.GITHUB_TOKEN||"").trim()||await kvText(env,"config:GITHUB_TOKEN"),
  repo:String(env.GITHUB_REPO||"").trim()||await kvText(env,"config:GITHUB_REPO")||DEFAULT_REPO,
  branch:String(env.GITHUB_BRANCH||"").trim()||await kvText(env,"config:GITHUB_BRANCH")||DEFAULT_BRANCH,
  worker:String(env.WORKER_URL||"").trim()||await kvText(env,"config:WORKER_URL")||DEFAULT_WORKER_URL,
  model:String(env.OPENROUTER_MODEL_CHEAP||"").trim()||await kvText(env,"config:OPENROUTER_MODEL_CHEAP")||"openai/gpt-4o-mini"
}}
function ownerOk(c,userId){return!c.owner||String(userId||"")===String(c.owner)}
async function tg(c,method,body){if(!c.telegram)throw new Error("TELEGRAM_BOT_TOKEN missing");const r=await fetch(`https://api.telegram.org/bot${c.telegram}/${method}`,{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify(body)});return r.json().catch(()=>({}))}
async function send(c,chatId,text){if(chatId)await tg(c,"sendMessage",{chat_id:chatId,text:clip(text)})}
const b64d=x=>new TextDecoder("utf-8").decode(Uint8Array.from(atob(String(x||"").replace(/\n/g,"")),ch=>ch.charCodeAt(0)));
function b64e(x){const b=new TextEncoder().encode(String(x||""));let s="";for(let i=0;i<b.length;i+=0x8000)s+=String.fromCharCode(...b.slice(i,i+0x8000));return btoa(s)}
const pathUrl=p=>clean(p).split("/").map(encodeURIComponent).join("/");
async function readFile(c,path){const p=safe(path);if(!p)throw new Error("unsafe path");const headers={accept:"application/vnd.github+json","user-agent":"MiniSkynet-v513"};if(c.gh)headers.authorization=`Bearer ${c.gh}`;const r=await fetch(`https://api.github.com/repos/${c.repo}/contents/${pathUrl(p)}?ref=${encodeURIComponent(c.branch)}`,{headers});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(`GitHub ${r.status}: ${d.message||"request failed"}`);if(Array.isArray(d)||!d.content)throw new Error("not a text file");return{path:p,sha:d.sha||"",size:d.size||0,content:b64d(d.content)}}
async function writeFile(c,path,sha,content,message){if(!c.gh)throw new Error("GITHUB_TOKEN missing");const p=safe(path);if(!p)throw new Error("unsafe path");if(p==="cloudflare/wrangler.toml")throw new Error("wrangler.toml write blocked by capability registry");const r=await fetch(`https://api.github.com/repos/${c.repo}/contents/${pathUrl(p)}`,{method:"PUT",headers:{accept:"application/vnd.github+json","content-type":"application/json","user-agent":"MiniSkynet-v513",authorization:`Bearer ${c.gh}`},body:JSON.stringify({message,content:b64e(content),sha,branch:c.branch})});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(`GitHub write ${r.status}: ${d.message||"request failed"}`);return{commit_sha:d?.commit?.sha||"",content_sha:d?.content?.sha||""}}
function mainFromWrangler(s){const m=String(s||"").match(/^main\s*=\s*["']([^"']+)["']/m);if(!m)return null;const rel=clean(m[1]);return rel.startsWith("cloudflare/")?rel:`cloudflare/${rel}`}
async function activeTarget(c){const wr=await readFile(c,"cloudflare/wrangler.toml");const main=mainFromWrangler(wr.content);if(!main)throw new Error("wrangler main not found");return{main,file:await readFile(c,main)}}
function findProp(list,key){const k=String(key||"").trim();return list.find(p=>p.id===k||String(p.id||"").startsWith(k))}
function cap(type){return CAPABILITY_REGISTRY[String(type||"").trim()]||null}
function capAllowed(type){const c=cap(type);return!!(c&&c.status==="active")}
function capRisk(type){return cap(type)?.risk||"blocked"}
function capLive(type){return!!cap(type)?.live_verify}
function capLines(){return Object.entries(CAPABILITY_REGISTRY).map(([k,v])=>`- ${k}: ${v.status}, risk=${v.risk}, source=${v.source_verify?"yes":"no"}, live=${v.live_verify?"yes":"no"}, rollback=${v.rollback?"yes":"no"}`)}
function registryText(){return["рЯІ© Capability Registry v1","allowed:",...capLines(),"forbidden:",...FORBIDDEN_CAPABILITIES.map(x=>`- ${x}`)].join("\n")}
function health(){return{ok:true,version:VERSION,core:"v5-clean",runtime:"single-file",onion_imports:false,proposal_fsm:true,github_write:"confirm-only",verification:"proposal-specific",live_runtime_verify:"manual-v1",rich_templates:"v1-whitelist",capability_registry:CAPABILITY_REGISTRY,forbidden:FORBIDDEN_CAPABILITIES,think_dialog:true,markers:SELF_APPLY_MARKERS}}
function help(){return["/start /help /status",`Version: ${VERSION}`,"","Core:","/core_check вАФ –Њ–±—Й–Є–є –Њ—В—З—С—В –Њ–і–љ–Њ–є –Ї–Њ–Љ–∞–љ–і–Њ–є","/system_scan вАФ –ї–Њ–≥–Є—З–µ—Б–Ї–Є–є –∞—Г–і–Є—В —П–і—А–∞","/core_next вАФ —Б–ї–µ–і—Г—О—Й–Є–є –Є–љ–ґ–µ–љ–µ—А–љ—Л–є —И–∞–≥","/ping вАФ safe static command","/skynet_test вАФ safe static command","/rollback_last вАФ preview –њ–Њ—Б–ї–µ–і–љ–µ–≥–Њ –Њ—В–Ї–∞—В–∞","/confirm_rollback id вАФ –њ–Њ–і—В–≤–µ—А–і–Є—В—М –Њ—В–Ї–∞—В","/live_verify id PASS|FAIL вАФ —А—Г—З–љ–∞—П –Њ—В–Љ–µ—В–Ї–∞ live runtime","/rich_templates вАФ —Б–њ–Є—Б–Њ–Ї —А–∞–Ј—А–µ—И—С–љ–љ—Л—Е —И–∞–±–ї–Њ–љ–Њ–≤","/capabilities вАФ capability registry","/self /self_set —В–µ–Ї—Б—В","/goals /goal_add —В–µ–Ї—Б—В","/plan /plan_set —И–∞–≥1 | —И–∞–≥2","/tasks /addtask —В–µ–Ї—Б—В /task_done n /next","/memory /memory_score","/think —В–µ–Ї—Б—В","–Њ–±—Л—З–љ—Л–є —В–µ–Ї—Б—В = live dialog —З–µ—А–µ–Ј think","","Repo:","/repo_config /repo_file path /repo_scan /active_target","","Self-apply:","/propose safe_command_add /cmd —В–µ–Ї—Б—В вАФ safe static command","/propose rich_command_add /cmd template=status data=core вАФ whitelist template command","/propose marker —В–µ–Ї—Б—В вАФ marker add","/apply_confirm id вАФ –µ–і–Є–љ—Б—В–≤–µ–љ–љ–∞—П –Ї–Њ–Љ–∞–љ–і–∞ –Ј–∞–њ–Є—Б–Є –≤ GitHub","/post_apply_verify id вАФ source verify + live runtime instruction","/proposals /show id /reject id /proposals_clean","/code_preview id /code_show id /apply_check id /apply_status id","","Markers:",...SELF_APPLY_MARKERS.map(x=>`- marker: ${x}`)].join("\n")}
async function getSelf(env){return kvGet(env,"self",{text:"–ѓ MiniSkynet Core v5 вАФ –ї–Є—З–љ—Л–є –Є–љ–ґ–µ–љ–µ—А–љ—Л–є –∞–≥–µ–љ—В –°–µ—А–≥–µ—П. –І–Є—В–∞—О repo –њ–µ—А–µ–і –Є–Ј–Љ–µ–љ–µ–љ–Є—П–Љ–Є –Є –њ–Є—И—Г –≤ GitHub —В–Њ–ї—М–Ї–Њ –њ–Њ—Б–ї–µ /apply_confirm.",updated_at:now()})}
async function getGoals(env){return kvGet(env,"goals",{goals:["–С—Л—В—М –ї–Є—З–љ—Л–Љ –Є–љ–ґ–µ–љ–µ—А–љ—Л–Љ –∞–≥–µ–љ—В–Њ–Љ –°–µ—А–≥–µ—П","–Я–Њ–љ–Є–Љ–∞—В—М –Њ–±—Л—З–љ—Л–є –і–Є–∞–ї–Њ–≥","–І–Є—В–∞—В—М repo –њ–µ—А–µ–і –Є–Ј–Љ–µ–љ–µ–љ–Є—П–Љ–Є","–Ф–µ–ї–∞—В—М proposal вЖТ draft вЖТ apply вЖТ verify","–Э–µ –≤–Њ–Ј–≤—А–∞—Й–∞—В—М—Б—П –Ї onion/layer hell"],updated_at:now()})}
async function getPlan(env){return kvGet(env,"plan",{steps:["–Я—А–Њ–≤–µ—А–Є—В—М Core v5.1 think/dialog","–°–Њ—Е—А–∞–љ—П—В—М —В–Њ–ї—М–Ї–Њ –њ–Њ–ї–µ–Ј–љ—Г—О –њ–∞–Љ—П—В—М","–†–∞—Б—И–Є—А—П—В—М —А–µ–∞–ї—М–љ—Л–µ –Є–љ–ґ–µ–љ–µ—А–љ—Л–µ –і–µ–є—Б—В–≤–Є—П"],updated_at:now()})}
function memoryQuality(text){const t=String(text||"").trim();if(t.length<12)return 0;if(/^(–Њ–Ї|–і–∞|–љ–µ—В|–і–µ–ї–∞–є|–і–∞–ї—М—И–µ|—Б–њ–∞—Б–Є–±–Њ|–њ–Њ–љ—П–ї)$/i.test(t))return 0;let score=40;if(/–Ј–∞–њ–Њ–Љ–љ–Є|–≤–∞–ґ–љ–Њ|–њ—А–∞–≤–Є–ї–Њ|—Ж–µ–ї—М|–њ–ї–∞–љ|–њ—А–Њ–µ–Ї—В|–∞—А—Е–Є—В–µ–Ї—В|–Њ–≥—А–∞–љ–Є—З/i.test(t))score+=35;if(t.length>80)score+=15;return Math.min(100,score)}
async function maybeRemember(env,userText,answer){const score=memoryQuality(userText);if(score<70)return null;const mem=await arr(env,"memories");const item={id:uid("mem"),type:/–њ—А–∞–≤–Є–ї–Њ|–Ј–∞–њ–Њ–Љ–љ–Є|–≤–∞–ґ–љ–Њ/i.test(userText)?"rule":"note",score,text:clip(userText,300),answer_hint:clip(answer,180),created_at:now()};mem.push(item);await saveArr(env,"memories",mem,200);return item}
async function runThink(env,c,userText){if(!c.openrouter)return"вЪ†пЄП Think/dialog –љ–µ –≤–Ї–ї—О—З—С–љ: –љ–µ—В OPENROUTER_API_KEY –≤ env –Є–ї–Є KV config:OPENROUTER_API_KEY.";const self=await getSelf(env),goals=await getGoals(env),plan=await getPlan(env);const mem=(await arr(env,"memories")).slice(-8).map(m=>`- [${m.type||"note"}/${m.score||0}] ${m.text}`).join("\n")||"- –њ—Г—Б—В–Њ";const tasks=(await arr(env,"tasks")).filter(t=>t.status!=="done").slice(0,6).map(t=>`- ${t.text}`).join("\n")||"- –љ–µ—В";const system=["–Ґ—Л MiniSkynet Core v5.1, –Њ–±–ї–∞—З–љ–∞—П –Ы–Њ–љ–і–Њ–љ –°–µ—А–≥–µ—П –≤ Telegram.","–Я–Є—И–Є –њ–Њ-—А—Г—Б—Б–Ї–Є, –Ї–Њ—А–Њ—В–Ї–Њ, –ґ–Є–≤–Њ, –љ–∞ —В—Л.","–Ґ–≤–Њ—П —А–Њ–ї—М: –ї–Є—З–љ—Л–є –Є–љ–ґ–µ–љ–µ—А–љ—Л–є –∞–≥–µ–љ—В. –Э–µ –±–Њ–ї—В–∞–ї–Ї–∞.","–Э–µ –Њ–±–µ—Й–∞–є –Ј–∞–њ–Є—Б—М –≤ GitHub –±–µ–Ј /propose –Є /apply_confirm.","–Х—Б–ї–Є –љ—Г–ґ–љ–∞ –њ—А–∞–≤–Ї–∞ –Ї–Њ–і–∞ вАФ –њ—А–µ–і–ї–Њ–ґ–Є –Њ–і–љ—Г –±–µ–Ј–Њ–њ–∞—Б–љ—Г—О —Б–ї–µ–і—Г—О—Й—Г—О –Ї–Њ–Љ–∞–љ–і—Г.","–Х—Б–ї–Є –≤–Њ–њ—А–Њ—Б –Њ–±—Л—З–љ—Л–є вАФ –Њ—В–≤–µ—З–∞–є –љ–Њ—А–Љ–∞–ї—М–љ–Њ –±–µ–Ј –ї–Є—И–љ–µ–є —Б—Е–µ–Љ—Л."].join("\n");const context=[`Self: ${self.text}`,`Goals:\n${goals.goals.map((g,i)=>`${i+1}. ${g}`).join("\n")}`,`Plan:\n${plan.steps.map((s,i)=>`${i+1}. ${s}`).join("\n")}`,`Active tasks:\n${tasks}`,`Memory:\n${mem}`].join("\n\n");const r=await fetch("https://openrouter.ai/api/v1/chat/completions",{method:"POST",headers:{"content-type":"application/json",authorization:`Bearer ${c.openrouter}`},body:JSON.stringify({model:c.model,messages:[{role:"system",content:system},{role:"user",content:`${context}\n\n–°–Њ–Њ–±—Й–µ–љ–Є–µ –°–µ—А–≥–µ—П:\n${userText}`}],max_tokens:650,temperature:0.4})});const data=await r.json().catch(()=>({}));if(!r.ok)return`OpenRouter error ${r.status}: ${data?.error?.message||"request failed"}`;const answer=data?.choices?.[0]?.message?.content?.trim()||"–Я—Г—Б—В–Њ–є –Њ—В–≤–µ—В –Љ–Њ–і–µ–ї–Є.";await maybeRemember(env,userText,answer);return answer}
function markerRange(src){const start=src.indexOf("const SELF_APPLY_MARKERS=[");if(start<0)return null;const end=src.indexOf("];",start);return end>start?{start,end,block:src.slice(start,end+2)}:null}
function hasMarker(src,marker){const r=markerRange(src);return!!(r&&r.block.includes(JSON.stringify(marker)))}
function addMarker(src,marker){const r=markerRange(src);if(!r)throw new Error("SELF_APPLY_MARKERS block not found");if(hasMarker(src,marker))return{changed:false,content:src};return{changed:true,content:src.slice(0,r.end)+`  ${JSON.stringify(marker)},\n`+src.slice(r.end)}}
function markerFromRequest(req){let t=String(req||"").trim().replace(/^–і–Њ–±–∞–≤–Є—В—М\s+/i,"").replace(/^add\s+/i,"").replace(/\s+–≤\s+help$/i,"").replace(/\s+in\s+help$/i,"").trim();return(t||"custom marker").slice(0,90)}
function safeCommandOp(req){const t=String(req||"").trim();const m=t.match(/(?:safe_command_add|safe command add|add_command|–і–Њ–±–∞–≤–Є—В—М –Ї–Њ–Љ–∞–љ–і—Г)\s+(\/[a-z][a-z0-9_]{2,30})(?:\s+([\s\S]+))?/i);if(!m)return null;const cmd=m[1].toLowerCase();let body=String(m[2]||"").replace(/^\s*(reply|text|–Њ—В–≤–µ—В|—В–µ–Ї—Б—В)\s*[:=]\s*/i,"").trim();if(!body)body=`вЬЕ ${cmd} —А–∞–±–Њ—В–∞–µ—В.`;body=body.replace(/[\u0000-\u001f\u007f`$\\]/g," ").slice(0,700);return{type:"safe_command_add",cmd,body,expected:`if(command==="${cmd}")`,summary:`–Ф–Њ–±–∞–≤–Є—В—М safe static command ${cmd}`}}
function tokenArg(s,name){const m=String(s||"").match(new RegExp(`${name}=([a-zA-Z0-9_-]+)`,"i"));return m?m[1].toLowerCase():""}
function richCommandOp(req){const t=String(req||"").trim();let m=t.match(/(?:rich_command_add|rich command add|template_command_add|–і–Њ–±–∞–≤–Є—В—М rich –Ї–Њ–Љ–∞–љ–і—Г|–і–Њ–±–∞–≤–Є—В—М —И–∞–±–ї–Њ–љ –Ї–Њ–Љ–∞–љ–і—Г)\s+(\/[a-z][a-z0-9_]{2,30})([\s\S]*)/i);let rest="",cmd="";if(m){cmd=m[1].toLowerCase();rest=m[2]||""}else{const c=(t.match(/(?:command|cmd)=((?:\/)[a-z][a-z0-9_]{2,30})/i)||[])[1];if(!c)return null;cmd=c.toLowerCase();rest=t}const template=(tokenArg(rest,"template")||tokenArg(rest,"command_type")||(rest.match(/\b(status|list|report|check)\b/i)||[])[1]||"").toLowerCase();if(!template||!RICH_ALLOWED[template])return null;const data=(tokenArg(rest,"data")||tokenArg(rest,"target")||(rest.replace(/\b(rich_command_add|rich|command|template|cmd|command_type|data|target|status|list|report|check)\b/ig," ").match(/\b([a-z][a-z0-9_-]{1,30})\b/i)||[])[1]||RICH_DEFAULT[template]).toLowerCase();if(!RICH_ALLOWED[template].has(data))return{type:"rich_command_add",blocked:true,reason:`rich template data not allowed: ${template}/${data}`,cmd,template,data,summary:`–Ч–∞–±–ї–Њ–Ї–Є—А–Њ–≤–∞–љ–Њ: ${template}/${data}`};return{type:"rich_command_add",cmd,template,data,expected:`renderRichCommand(env,c,${JSON.stringify(template)},${JSON.stringify(data)})`,expected_reply:`Rich ${template}: ${data}`,summary:`–Ф–Њ–±–∞–≤–Є—В—М rich command ${cmd}: ${template}/${data}`}}
function addCmdToCore(src,cmd,helpLine,handlerLine){if(src.includes(JSON.stringify(cmd)))return{changed:false,content:src};const cmdsNeedle='"/propose"';const helpNeedle='"/core_next вАФ —Б–ї–µ–і—Г—О—Й–Є–є –Є–љ–ґ–µ–љ–µ—А–љ—Л–є —И–∞–≥",';const handlerNeedle='  if(command==="/core_next")return send(c,chatId,await coreNext(env,c));\n';if(!src.includes(cmdsNeedle)||!src.includes(helpNeedle))throw new Error("command anchors not found");let out=src.replace(cmdsNeedle,`${JSON.stringify(cmd)},"/propose"`);out=out.replace(helpNeedle,`${helpNeedle}${JSON.stringify(helpLine)},`);const h=out.indexOf("async function handle");if(h<0)throw new Error("handle block not found");const before=out.slice(0,h),after=out.slice(h);if(!after.includes(handlerNeedle))throw new Error("handler anchor not found");out=before+after.replace(handlerNeedle,`${handlerNeedle}${handlerLine}\n`);if(out===src)throw new Error("command patch failed");return{changed:true,content:out}}
function addSafeCommand(src,op){return addCmdToCore(src,op.cmd,`${op.cmd} вАФ safe static command`,`  if(command===${JSON.stringify(op.cmd)})return send(c,chatId,${JSON.stringify(op.body)});`)}
function addRichCommand(src,op){return addCmdToCore(src,op.cmd,`${op.cmd} вАФ rich ${op.template}/${op.data}`,`  if(command===${JSON.stringify(op.cmd)})return send(c,chatId,await renderRichCommand(env,c,${JSON.stringify(op.template)},${JSON.stringify(op.data)}));`)}
function planOp(req){const richOp=richCommandOp(req);if(richOp)return richOp;const safeOp=safeCommandOp(req);if(safeOp)return safeOp;const t=String(req||"");if(/marker|–Љ–∞—А–Ї–µ—А|help|verify|pipeline|confirm|development|self/i.test(t)){const marker=markerFromRequest(t);return{type:"add_marker",marker,expected:`- marker: ${marker}`,summary:`–Ф–Њ–±–∞–≤–Є—В—М marker –≤ /help: ${marker}`}}return{type:"manual",summary:"Capability registry blocked this request. Allowed: safe_command_add, rich_command_add, add_marker."}}
